1232	// acquisition. Callers must hold withTrackerLock(projectRoot) before calling.
1233	// Used by Run() to fold tracker commit, checkpoint synthesis, and worktree
1234	// creation into a single critical section so concurrent workers do not race
1235	// on the parent's HEAD ref (regression: niflheim concurrent `ddx work` hit
1236	// "cannot lock ref 'HEAD'" between unlocked CommitTracker and SynthesizeCommit).
1237	func commitTrackerLocked(projectRoot string) error {
1238		trackerFile := filepath.Join(projectRoot, ".ddx", "beads.jsonl")
1239		info, err := os.Stat(trackerFile)
1240		if err != nil {
1241			if os.IsNotExist(err) {
1242				return nil
1243			}
1244			return fmt.Errorf("checking tracker file: %w", err)
1245		}
1246		if info.IsDir() {
1247			return nil
1248		}
1249	
1250		out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
1251		if err != nil || strings.TrimSpace(string(out)) != "true" {
1252			return nil
1253		}
1254	
1255		msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))
1256	
1257		// Re-check inside the lock: a sibling worker may have already
1258		// committed the tracker changes between our pre-lock check and now.
1259		diff, err := internalgit.Command(context.Background(), projectRoot, "diff", "--", ".ddx/beads.jsonl").Output()
1260		if err != nil {
1261			return fmt.Errorf("checking tracker diff: %w", err)
1262		}
1263		if strings.TrimSpace(string(diff)) == "" {
1264			untracked, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "--others", "--exclude-standard", ".ddx/beads.jsonl").Output()
1265			if err != nil {
1266				return fmt.Errorf("checking tracker untracked: %w", err)
1267			}
1268			if strings.TrimSpace(string(untracked)) == "" {
1269				return nil

1269				return nil
1270			}
1271		}
1272	
1273		commitOut, err := internalgit.Command(context.Background(), projectRoot, "add", ".ddx/beads.jsonl").CombinedOutput()
1274		if err != nil {
1275			return fmt.Errorf("staging tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1276		}
1277		// `git commit` would fail with "nothing to commit" if the file's
1278		// content is byte-identical to HEAD even though `git diff` saw a
1279		// diff (e.g. mode/whitespace race). Bail cleanly in that case.
1280		if cached, err := internalgit.Command(context.Background(), projectRoot, "diff", "--cached", "--", ".ddx/beads.jsonl").Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
1281			return nil
1282		}
1283		commitOut, err = internalgit.Command(context.Background(), projectRoot, "commit", "--no-verify", "-m", msg).CombinedOutput()
1284		if err != nil {
1285			return fmt.Errorf("committing tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1286		}
1287		return nil
1288	}
