82	// TestBuildIterationCommitMessage_IterationBlock verifies that the ddx-iteration
83	// JSON block is present and well-formed with the correct field values.
84	func TestBuildIterationCommitMessage_IterationBlock(t *testing.T) {
85		res := minimalResult()
86		msg := BuildIterationCommitMessage(res)
87	
88		// Locate the ddx-iteration prefix.
89		const prefix = "ddx-iteration: "
90		idx := strings.Index(msg, prefix)
91		if idx == -1 {
92			t.Fatalf("message missing %q block", prefix)
93		}
94	
95		// Extract the JSON portion: from '{' to the matching '}'.
96		jsonStart := strings.Index(msg[idx:], "{")
97		if jsonStart == -1 {
98			t.Fatalf("ddx-iteration block has no JSON object")
99		}
100		jsonStart += idx
101		// Find the closing brace of the top-level object.
102		jsonEnd := strings.Index(msg[jsonStart:], "\n\n")
103		var raw string
104		if jsonEnd == -1 {
105			raw = msg[jsonStart:]
106			// Trim any trailing trailer lines after the JSON.
107			if i := strings.Index(raw, "\nDdx-"); i != -1 {
108				raw = raw[:i]
109			}
110		} else {
111			raw = msg[jsonStart : jsonStart+jsonEnd]
112		}
113		raw = strings.TrimSpace(raw)
114	
115		var block ExecuteBeadIterationBlock
116		if err := json.Unmarshal([]byte(raw), &block); err != nil {
117			t.Fatalf("ddx-iteration JSON parse error: %v\nraw=%q", err, raw)
118		}
119	
120		if block.BeadID != res.BeadID {
121			t.Errorf("block.bead_id = %q, want %q", block.BeadID, res.BeadID)
122		}
123		if block.AttemptID != res.AttemptID {
124			t.Errorf("block.attempt_id = %q, want %q", block.AttemptID, res.AttemptID)
125		}
126		if block.SessionID != res.SessionID {
127			t.Errorf("block.session_id = %q, want %q", block.SessionID, res.SessionID)
128		}
129		if block.Harness != res.Harness {
130			t.Errorf("block.harness = %q, want %q", block.Harness, res.Harness)
131		}
132		if block.Model != res.Model {
133			t.Errorf("block.model = %q, want %q", block.Model, res.Model)
134		}
135		if block.TotalTokens != res.Tokens {
136			t.Errorf("block.total_tokens = %d, want %d", block.TotalTokens, res.Tokens)
137		}
138		if block.BaseRev != res.BaseRev {
139			t.Errorf("block.base_rev = %q, want %q", block.BaseRev, res.BaseRev)
140		}
141		if block.ResultRev != res.ResultRev {
142			t.Errorf("block.result_rev = %q, want %q", block.ResultRev, res.ResultRev)
143		}
144		if block.ExecutionBundle != res.ExecutionDir {
145			t.Errorf("block.execution_bundle = %q, want %q", block.ExecutionBundle, res.ExecutionDir)
146		}
147	}
